var groups={};
rawData.rows.forEach(function(r){
  if(!groups[r.g]) groups[r.g]=[];
  groups[r.g].push(r.v);
});
var cats=Object.keys(groups);
function kde(vals,x,bw){
  var s=0;
  for(var i=0;i<vals.length;i++){
    var u=(x-vals[i])/bw;
    s+=Math.exp(-0.5*u*u);
  }
  return s/(vals.length*bw*Math.sqrt(2*Math.PI));
}
var seriesData=[];
cats.forEach(function(g,gi){
  var vals=groups[g].slice().sort(function(a,b){return a-b;});
  var bw=0.8;
  var densities=vals.map(function(v){return kde(vals,v,bw);});
  var maxD=0;
  densities.forEach(function(d){if(d>maxD) maxD=d;});
  vals.forEach(function(v,vi){
    var spread=0.35*(densities[vi]/maxD);
    if(spread<0.03) spread=0.03;
    var jitter=(Math.random()-0.5)*2*spread;
    seriesData.push([gi+jitter, v]);
  });
});
transformedData={data:seriesData, cats:cats};
